			]
		},
		"show": {
			"aliases": [
				"country"
			],
			"label": "whitelist",
			"example": "ES",
			"type": "string",
			"suggestedvalues": [
				"arts"
			],
			"description": "Whitelist (e.g. arts) or country code (e.g. ES) or property (e.g. P214) to show. If not specified, then every supported identifier will be displayed."
		}
	},
	"format": "\n{{_|_=_}}\n",
